             && self.pending_memdb_direct_upserts.borrow().is_empty()
             && !self.pending_local_live_vtab_preserve_once.get()
         {
+            // Autoincrement tables track their next-rowid high-water-mark in
+            // sqlite_sequence. `INSERT` on an AUTOINCREMENT column doesn't bump
+            // schema_cookie, so if we only relied on the cookie match we would
+            // silently serve a stale `last_insert_rowid` / next-auto-rowid hint.
+            // Match the Lightweight refresh path in
+            // `try_refresh_prepared_metadata_if_stale` and refresh the cache
+            // here when we have any autoincrement tables to track.
+            if !self.autoincrement_tables.borrow().is_empty() {
+                let cache = self.read_sqlite_sequence_cache_in_txn(cx, txn)?;
+                *self.sqlite_sequence_cache.borrow_mut() = cache;
+            }
             *self.memdb_visible_commit_seq.borrow_mut() = bound_visible_commit_seq;
             *self.change_counter.borrow_mut() = change_counter;
             return Ok(());
